import React from "react";
import { useNavigate } from "react-router-dom";

function LandingPage() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* LEFT CONTENT */}
      <div style={styles.left}>
        <h1 style={styles.heading}>
          Find & Book <span style={{ color: "#2563EB" }}>Doctors</span>
        </h1>

        <p style={styles.text}>
          Easily connect with experienced doctors and manage your appointments
          in one place. Your health made simple.
        </p>

        <div style={styles.buttons}>
          <button
            style={styles.primaryBtn}
            onClick={() => navigate("/login")}
          >
            Get Started
          </button>

          <button
            style={styles.secondaryBtn}
            onClick={() => navigate("/register")}
          >
            Create Account
          </button>
        </div>
      </div>

      {/* RIGHT IMAGE */}
      <div style={styles.right}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/3774/3774299.png"
          alt="doctor"
          style={styles.image}
        />
      </div>

    </div>
  );
}

export default LandingPage;

const styles = {
  container: {
    display: "flex",
    height: "100vh",
    padding: "0 60px",
    alignItems: "center",
    justifyContent: "space-between",
    fontFamily: "Segoe UI, sans-serif",
    background: "linear-gradient(135deg, #f0f9ff, #ecfeff)",
  },

  left: {
    flex: 1,
    maxWidth: "500px",
  },

  heading: {
    fontSize: "42px",
    marginBottom: "20px",
    lineHeight: "1.2",
    color: "#1f2937",
  },

  text: {
    fontSize: "16px",
    color: "#555",
    marginBottom: "30px",
    lineHeight: "1.6",
  },

  buttons: {
    display: "flex",
    gap: "15px",
  },

  primaryBtn: {
    padding: "12px 24px",
    backgroundColor: "#2563EB",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    fontWeight: "600",
  },

  secondaryBtn: {
    padding: "12px 24px",
    backgroundColor: "white",
    border: "1px solid #2563EB",
    color: "#2563EB",
    borderRadius: "8px",
    cursor: "pointer",
    fontWeight: "600",
  },

  right: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
  },

  image: {
    width: "65%",
    maxWidth: "350px",
  },
};
